set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
WORKFLOW="ComfyUI 节点工作流搭建与复用（工程链）(Decay risk: medium) last_updated: 2026-06-22"

usage() {
  cat <<EOF
comfyui-decay-risk-medium-last-u.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./comfyui-decay-risk-medium-last-u.sh             # interactive
  ./comfyui-decay-risk-medium-last-u.sh --dry-run
  ./comfyui-decay-risk-medium-last-u.sh --json
  ./comfyui-decay-risk-medium-last-u.sh --explain
  ./comfyui-decay-risk-medium-last-u.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "ComfyUI 节点工作流搭建与复用（工程链）(Decay risk: medium) last_updated: 2026-06-22" 工作流。

一句话: 把生成管线搭成可复现、可参数化、可批量、可分享的节点图 —— 从模板起步、subgraph 模块化、API 队列批产、JSON 分享复用。从「手点出一张图」到「可工程化复用的流水线」。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**从模板起步**：用 ComfyUI 官方模板工作流或社区 JSON 起步，不从空白搭。(evidence: [T03-S004])"
  "**导入并补依赖**：拖入 workflow 图/JSON 加载节点；用 Manager 装缺失自定义节点、映射本地 checkpoint/LoRA/VAE 路径（JSON 不含模型文件与本地路径）。(evidence: [T03-S003])"
  "**连管线**：Load→CLIP Encode→（ControlNet/IPAdapter/LoRA）→KSampler→VAE Decode→放大→Save，按需求接好。"
  "**参数化关键节点**：把要反复改的值（prompt/seed/分辨率）暴露为可调输入。"
  "**批量队列**：用 batch / 多 seed / 队列 Queue 一次跑多张。"
  "**导出 JSON 分享**：导出 workflow JSON（PNG 也内嵌），交付/归档/复用。(evidence: [T03-S003])"
)
declare -a FAILURE_MODES=(
  "**复用工作流缺节点/缺模型**：拖入别人 JSON 满屏红框 —— 先看来源/格式，用 Manager 装缺失节点，再映射 checkpoint/LoRA/VAE 路径，最后才跑。"
  "**不参数化导致批产手忙**：每次改 prompt 要在大图里找节点 —— 把可变输入暴露/用 primitive 节点集中管理。"
  "**本机依赖未声明**：分享 JSON 给别人跑不起来 —— 附带自定义节点清单 + 模型清单，或用 Manager 的依赖快照。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "comfyui-decay-risk-medium-last-u-walkthrough"
fi
